package org.fintech.service;


import org.fintech.security.JwtService;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;

import java.util.*;
import java.util.concurrent.ConcurrentHashMap;

@Service
public class AuthService {

    private final JwtService jwtService;
    private final PasswordEncoder passwordEncoder;

    // MVP: usuários em memória. Na Fase 2, troque por tabela DynamoDB.
    private final Map<String, AppUser> users = new ConcurrentHashMap<>();

    public AuthService(JwtService jwtService, PasswordEncoder passwordEncoder) {
        this.jwtService = jwtService;
        this.passwordEncoder = passwordEncoder;
    }

    public AppUser register(String email, String rawPassword) {
        if (users.values().stream().anyMatch(u -> u.getEmail().equals(email))) {
            throw new IllegalArgumentException("E-mail já cadastrado");
        }
        AppUser user = new AppUser(
                UUID.randomUUID().toString(),
                email,
                passwordEncoder.encode(rawPassword)
        );
        users.put(user.getId(), user);
        return user;
    }

    public String login(String email, String rawPassword) {
        AppUser user = users.values().stream()
                .filter(u -> u.getEmail().equals(email))
                .findFirst()
                .orElseThrow(() -> new IllegalArgumentException("Credenciais inválidas"));

        if (!passwordEncoder.matches(rawPassword, user.getPasswordHash())) {
            throw new IllegalArgumentException("Credenciais inválidas");
        }

        return jwtService.generateToken(user.getId(), user.getEmail());
    }
}

package org.fintech.service;

import lombok.RequiredArgsConstructor;
import org.fintech.domain.entity.Tenant;
import org.fintech.domain.repository.TenantRepository;
import org.fintech.security.JwtService;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;

@Service
@RequiredArgsConstructor
public class AuthService {

    private final TenantRepository tenantRepository;
    private final JwtService jwtService;
    private final PasswordEncoder passwordEncoder;

    /**
     * Registrar novo tenant
     */
    public void register(String email, String password) {
        // Validar se já existe
        if (tenantRepository.findById(email).isPresent()) {
            throw new IllegalArgumentException("Tenant já registrado: " + email);
        }

        // Criar novo tenant
        var tenant = Tenant.builder()
                .tenantId(email)
                .email(email)
                .name(email.split("@")[0])
                .passwordHash(passwordEncoder.encode(password))
                .build();

        tenantRepository.save(tenant);
    }

    /**
     * Fazer login e retornar token JWT
     */
    public String login(String email, String password) {
        var tenant = tenantRepository.findById(email)
                .orElseThrow(() -> new IllegalArgumentException("Credenciais inválidas"));

        if (!passwordEncoder.matches(password, tenant.getPasswordHash())) {
            throw new IllegalArgumentException("Credenciais inválidas");
        }

        return jwtService.generateToken(tenant.getTenantId(), tenant.getEmail());
    }

    /**
     * Validar token JWT
     */
    public boolean isValidToken(String token) {
        return jwtService.isValid(token);
    }

    /**
     * Extrair tenantId do token
     */
    public String extractTenantId(String token) {
        return jwtService.extractTenantId(token);
    }

    /**
     * Extrair email do token
     */
    public String extractEmail(String token) {
        return jwtService.extractEmail(token);
    }
}

